class Solution:
    def relativeSortArray(self, arr1, arr2):
        out = []
        rank = {v: i for i, v in enumerate(arr2)}
        for v in arr2:
            for x in arr1:
                if x == v:
                    out.append(x)
        rest = sorted(x for x in arr1 if x not in rank)
        return out + rest

