class Solution:
    def relativeSortArray(self, arr1, arr2):
        rank = {v: i for i, v in enumerate(arr2)}
        big = len(arr2)
        return sorted(arr1, key=lambda x: (rank.get(x, big), x if x not in rank else 0))

