var relativeSortArray = function(arr1, arr2) {
    const rank = new Map();
    arr2.forEach((v, i) => rank.set(v, i));
    const big = arr2.length;
    return arr1.slice().sort((a, b) => {
        const ra = rank.has(a) ? rank.get(a) : big;
        const rb = rank.has(b) ? rank.get(b) : big;
        if (ra !== rb) return ra - rb;
        const va = rank.has(a) ? 0 : a;
        const vb = rank.has(b) ? 0 : b;
        return va - vb;
    });
};
